import{_ as a,o as t,c as o,a6 as s}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"Running an OoO Data Provider","description":"","frontmatter":{},"headers":[],"relativePath":"ooo/guide/run-provider.md","filePath":"ooo/guide/run-provider.md"}'),i={name:"ooo/guide/run-provider.md"};function n(r,e,d,h,l,c){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="running-an-ooo-data-provider" tabindex="-1">Running an OoO Data Provider <a class="header-anchor" href="#running-an-ooo-data-provider" aria-label="Permalink to &quot;Running an OoO Data Provider&quot;">​</a></h1><p>This guide covers installing, configuring and running <a href="https://github.com/unification-com/xfund-router/tree/main/go-ooo" target="_blank" rel="noreferrer"><code>go-ooo</code></a> — the Go implementation of the OoO Provider application. A provider oracle listens for on-chain data requests on the xFUND Router, prices the requested pair from decentralised-exchange (DEX) liquidity, fulfils the request on-chain, and earns an <code>xFUND</code> fee for doing so.</p><div class="tip custom-block"><p class="custom-block-title">Who runs a provider?</p><p>The Unification Foundation runs the default providers listed in <a href="./../providers.html">Provider Addresses</a>, so <strong>consumers do not need to run anything</strong> — they simply send requests to a registered provider. This guide is for anyone who wants to operate <strong>their own</strong> provider oracle.</p></div><h2 id="how-a-provider-works" tabindex="-1">How a provider works <a class="header-anchor" href="#how-a-provider-works" aria-label="Permalink to &quot;How a provider works&quot;">​</a></h2><ol><li>A consumer contract sends a data request to the <a href="./../contracts.html">Router</a>, paying the provider&#39;s <code>xFUND</code> fee.</li><li><code>go-ooo</code> detects the request event on-chain.</li><li>It resolves the requested <code>BASE.TARGET</code> pair against the supported DEXs and computes a robust, liquidity-weighted mean price (see the <a href="./ooo_api.html">OoO Data API guide</a>).</li><li>It fulfils the request by calling back into the Router, which forwards the price to the consumer contract.</li><li>The fee accrues in the Router and can be withdrawn at any time.</li></ol><p>The set of priceable DEXs and pairs is driven by the <a href="https://ooo-dex.unification.io" target="_blank" rel="noreferrer">dex-pair-verify</a> catalogue, which <code>go-ooo</code> polls periodically (the &quot;DEX export&quot;). You can use the Foundation&#39;s public catalogue or run your own.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li><strong>Go 1.18+</strong> to build from source.</li><li>A <strong>wallet</strong> (private key) with <strong>native gas</strong> on each chain you intend to serve. You do <strong>not</strong> need to hold <code>xFUND</code> to run a provider — you earn it; you only need native currency (ETH, MATIC, BONE, QOM, …) to pay gas for fulfilment transactions.</li><li><strong>RPC endpoints</strong> for each chain. An HTTP endpoint is required (it carries calls, <code>eth_getLogs</code> event detection and transaction sends); a WebSocket endpoint is optional and used only for low-latency event subscriptions, with HTTP-only (poll mode) fully supported. A <strong>paid or dedicated RPC is strongly recommended</strong> — see <a href="#a-note-on-rpc-endpoints">A note on RPC endpoints</a>.</li><li>A <strong><a href="https://thegraph.com" target="_blank" rel="noreferrer">The Graph</a> Network API key</strong> — <strong>effectively required.</strong> DEX pricing reads the DEX subgraphs over The Graph&#39;s decentralised network, and without a key <strong>no subgraph-backed source is priceable</strong>, leaving the oracle with almost nothing to serve. See <a href="#the-graph-api-key">The Graph API key</a>.</li><li>A <strong>database</strong> — SQLite by default (zero-config), or PostgreSQL for production.</li><li>Optionally, access to a <strong>dex-pair-verify export API</strong>. The default is Unification&#39;s public catalogue; you can point at your own instance instead.</li></ul><h2 id="_1-install" tabindex="-1">1. Install <a class="header-anchor" href="#_1-install" aria-label="Permalink to &quot;1. Install&quot;">​</a></h2><p>You can either <strong>download a pre-built release binary</strong> (quickest, no toolchain needed) or <strong>build from source</strong>.</p><h3 id="option-a-—-download-a-release-binary" tabindex="-1">Option A — download a release binary <a class="header-anchor" href="#option-a-—-download-a-release-binary" aria-label="Permalink to &quot;Option A — download a release binary&quot;">​</a></h3><p>Pre-built binaries for Linux, macOS and Windows (x86_64) are attached to each <a href="https://github.com/unification-com/xfund-router/releases" target="_blank" rel="noreferrer">GitHub release</a>. Download the archive for your platform, verify it against the release&#39;s <code>checksums.txt</code>, extract it, and put <code>go-ooo</code> on your <code>PATH</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># example: Linux x86_64 — replace VERSION with the latest release (e.g. 0.6.0)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -LO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/unification-com/xfund-router/releases/download/vVERSION/go-ooo_vVERSION_linux_x86_64.tar.gz</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-ooo_vVERSION_linux_x86_64.tar.gz</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/bin/</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Apple Silicon / ARM</p><p>The release archives are x86_64 only. On an ARM host (Apple Silicon, ARM Linux), build from source instead.</p></div><h3 id="option-b-—-build-from-source" tabindex="-1">Option B — build from source <a class="header-anchor" href="#option-b-—-build-from-source" aria-label="Permalink to &quot;Option B — build from source&quot;">​</a></h3><p>Requires <strong>Go 1.18+</strong>. <code>go-ooo</code> lives in the <code>go-ooo/</code> subdirectory of the <a href="https://github.com/unification-com/xfund-router" target="_blank" rel="noreferrer"><code>xfund-router</code></a> repository:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/unification-com/xfund-router.git</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xfund-router/go-ooo</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># install the binary to $GOPATH/bin</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ...or build it into ./build/go-ooo</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>Either way, confirm it runs:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span></span></code></pre></div><h2 id="_2-initialise" tabindex="-1">2. Initialise <a class="header-anchor" href="#_2-initialise" aria-label="Permalink to &quot;2. Initialise&quot;">​</a></h2><p><code>init</code> writes a default configuration and creates your keystore. <code>&lt;network&gt;</code> is one of <code>dev</code>, <code>sepolia</code>, <code>mainnet</code>, <code>polygon</code>, <code>shibarium</code>, <code>puppynet</code> or <code>qom</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mainnet</span></span></code></pre></div><p>By default everything is stored under <code>$HOME/.go-ooo</code>. Use <code>--home</code> to choose another location (useful for running separate instances):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sepolia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --home</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.go-ooo_sepolia</span></span></code></pre></div><p>During initialisation you will be asked whether to <strong>generate a new key</strong> or <strong>import an existing private key</strong>, and to set a <strong>keystore passphrase</strong>. The passphrase is required both to start the oracle (to decrypt the key) and to run admin commands.</p><div class="warning custom-block"><p class="custom-block-title">Keep the passphrase safe</p><p>Without the passphrase you cannot run the oracle or recover the key. Back up the keystore file (<code>$HOME/.go-ooo/keystore.json</code>) and remember your passphrase. For unattended operation you can save the passphrase to a file (e.g. <code>$HOME/.go-ooo/pass.txt</code>) and pass it with <code>--pass</code> — keep that file readable only by the service account.</p></div><p>This produces <code>$HOME/.go-ooo/config.toml</code>, an SQLite database, and <code>keystore.json</code>. The home directory is created <code>0700</code>, and the config and keystore <code>0600</code>, because they can hold secrets.</p><h2 id="_3-configure" tabindex="-1">3. Configure <a class="header-anchor" href="#_3-configure" aria-label="Permalink to &quot;3. Configure&quot;">​</a></h2><p>Open <code>config.toml</code> and fill in the values for your environment. The most important sections:</p><h3 id="chain-or-chains" tabindex="-1"><code>[chain]</code> (or <code>[[chains]]</code>) <a class="header-anchor" href="#chain-or-chains" aria-label="Permalink to &quot;`[chain]` (or `[[chains]]`)&quot;">​</a></h3><p>The chain to serve. Run <strong>one</strong> network with a single <code>[chain]</code> block, or <strong>several</strong> from one process with a <code>[[chains]]</code> array (see <a href="#multiple-networks-from-one-process">Multiple networks</a>).</p><table tabindex="0"><thead><tr><th>Key</th><th>Description</th></tr></thead><tbody><tr><td><code>contract_address</code></td><td>The Router contract address (pre-filled from the network defaults).</td></tr><tr><td><code>network_id</code></td><td>The chain&#39;s network id (e.g. <code>1</code> for Ethereum mainnet).</td></tr><tr><td><code>eth_http_host</code></td><td><strong>Required.</strong> RPC HTTP endpoint — carries calls, event detection and tx sends.</td></tr><tr><td><code>eth_ws_host</code></td><td>Optional WebSocket endpoint for low-latency event subscriptions. Leave blank for HTTP poll mode.</td></tr><tr><td><code>event_scan_batch_blocks</code></td><td>Max block range per <code>eth_getLogs</code> scan (default <code>2000</code>). Lower it for RPCs that throttle wide ranges.</td></tr><tr><td><code>first_block</code></td><td>Block to start scanning for jobs from — generally the block you registered as a provider.</td></tr><tr><td><code>gas_limit</code></td><td>Gas limit for fulfilment transactions.</td></tr><tr><td><code>max_gas_price</code></td><td>Maximum gas price you will pay to fulfil a request.</td></tr><tr><td><code>eip1559</code></td><td>Send EIP-1559 (type-2) dynamic-fee transactions; safe to leave <code>true</code> (falls back to legacy pricing on pre-London chains).</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Set <code>max_gas_price</code> to suit the chain</p><p>A <code>max_gas_price</code> set below the chain&#39;s live gas price means your fulfilments never get included. Some chains quote gas very differently — QoM&#39;s live gas price, for example, sits at around <code>18000000000</code> gwei — so check the target chain and set this at or above its going rate.</p></div><h3 id="a-note-on-rpc-endpoints" tabindex="-1">A note on RPC endpoints <a class="header-anchor" href="#a-note-on-rpc-endpoints" aria-label="Permalink to &quot;A note on RPC endpoints&quot;">​</a></h3><p>The oracle polls <code>eth_getLogs</code> continuously to detect requests, and sends every fulfilment through the same HTTP endpoint, so <strong>a paid or dedicated RPC is strongly recommended for production.</strong> Free public endpoints routinely throttle (HTTP 429), cap the block range per <code>eth_getLogs</code> call, or return malformed responses under load — any of which stalls request detection and fulfilment.</p><ul><li>Use a <strong>paid tier</strong> (Infura, Alchemy, dRPC, …) or the chain&#39;s <strong>own official node</strong> for <code>eth_http_host</code> — this is the endpoint that must be reliable.</li><li>A WebSocket endpoint (<code>eth_ws_host</code>) only speeds up event detection; HTTP poll mode works fine without one, so if your provider throttles WSS, leave it blank.</li><li>If you fall a long way behind on a rate-limited endpoint, advance the scan cursor at start with <code>--first-block</code>, and lower <code>event_scan_batch_blocks</code> for RPCs that reject wide ranges.</li></ul><h3 id="database" tabindex="-1"><code>[database]</code> <a class="header-anchor" href="#database" aria-label="Permalink to &quot;`[database]`&quot;">​</a></h3><p><code>dialect</code> is <code>sqlite</code> (default) or <code>postgres</code>. SQLite needs only <code>storage</code> (a file path); PostgreSQL needs <code>host</code>, <code>port</code>, <code>database</code>, <code>user</code> and <code>password</code>.</p><h3 id="jobs-and-jobs-dex-export" tabindex="-1"><code>[jobs]</code> and <code>[jobs.dex_export]</code> <a class="header-anchor" href="#jobs-and-jobs-dex-export" aria-label="Permalink to &quot;`[jobs]` and `[jobs.dex_export]`&quot;">​</a></h3><p><code>check_duration</code> (seconds between request polls), <code>wait_confirmations</code> (blocks to wait before fulfilling) and <code>max_job_age</code> (seconds before a request is abandoned) live in <code>[jobs]</code>.</p><p><code>[jobs.dex_export]</code> points <code>go-ooo</code> at the dex-pair-verify catalogue of priceable DEXs and pairs. <code>base_url</code> defaults to the Foundation&#39;s public catalogue (<code>https://ooo-dex.unification.io/api/ooo/v1</code>); on the real networks the provider authenticates with its on-chain-registered wallet. Point it at your own instance, or leave it <strong>empty</strong> to skip the sync and price from whatever catalogue is already persisted in the database.</p><h3 id="keystorage-serve-prometheus" tabindex="-1"><code>[keystorage]</code>, <code>[serve]</code>, <code>[prometheus]</code> <a class="header-anchor" href="#keystorage-serve-prometheus" aria-label="Permalink to &quot;`[keystorage]`, `[serve]`, `[prometheus]`&quot;">​</a></h3><p><code>[keystorage]</code> holds the keystore <code>account</code> and <code>file</code> (set by <code>init</code>). <code>[serve]</code> is the host/port of the local admin HTTP API used by the admin and query commands. <code>[prometheus]</code> is the port that serves metrics.</p><h3 id="subchain" tabindex="-1"><code>[subchain]</code> <a class="header-anchor" href="#subchain" aria-label="Permalink to &quot;`[subchain]`&quot;">​</a></h3><p><code>[subchain]</code> holds per-chain RPCs the DEX modules use to look up the latest block number when querying subgraphs. The same &quot;use a reliable endpoint&quot; advice as above applies.</p><h3 id="the-graph-api-key" tabindex="-1">The Graph API key <a class="header-anchor" href="#the-graph-api-key" aria-label="Permalink to &quot;The Graph API key&quot;">​</a></h3><p>DEX pricing reads each supported DEX&#39;s subgraph over <a href="https://thegraph.com" target="_blank" rel="noreferrer">The Graph</a>&#39;s decentralised network — a <strong>paid, key-gated</strong> service. Set your key in <code>[api_keys].graph_network_key</code>.</p><div class="danger custom-block"><p class="custom-block-title">The Graph key is effectively required</p><p>Without a valid <code>graph_network_key</code>, <strong>no subgraph-backed DEX source is priceable</strong> — which is almost every source — so the oracle has nothing to serve and requests go unfulfilled. Treat it as a hard requirement for any real deployment. The only exceptions are non-EVM sources such as Cosmos/Osmosis, which do not use The Graph.</p></div><div class="tip custom-block"><p class="custom-block-title">The full annotated config</p><p>Every field is documented inline in the generated <code>config.toml</code>. The template is also in the <a href="https://github.com/unification-com/xfund-router/tree/main/go-ooo#readme" target="_blank" rel="noreferrer">go-ooo README</a>.</p></div><h2 id="_4-register-the-provider-key" tabindex="-1">4. Register the provider key <a class="header-anchor" href="#_4-register-the-provider-key" aria-label="Permalink to &quot;4. Register the provider key&quot;">​</a></h2><p>If you initialised with your own key (i.e. not the pre-registered <code>dev</code> test key), you must register your wallet as a provider on-chain. First ensure the wallet holds <strong>native gas</strong> on the target chain, then set your global fee:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> register</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1000000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/pass.txt</span></span></code></pre></div><p>The fee is expressed in <code>xFUND</code>&#39;s smallest unit (<code>xFUND</code> has 9 decimals), so <code>1000000</code> is <code>0.001 xFUND</code>, <code>41500000</code> is <code>0.0415 xFUND</code>, and so on.</p><p>If you run several chains, target one with <code>--chain &lt;name|network_id&gt;</code>.</p><h2 id="_5-start-the-oracle" tabindex="-1">5. Start the oracle <a class="header-anchor" href="#_5-start-the-oracle" aria-label="Permalink to &quot;5. Start the oracle&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pass</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/pass.txt</span></span></code></pre></div><p>Without <code>--pass</code> you are prompted for the passphrase interactively. <code>--home</code> selects a non-default config location. Starting the service brings up the admin HTTP API (<code>[serve]</code>) and the Prometheus metrics endpoint (<code>[prometheus]</code>), and begins detecting and fulfilling requests.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># non-default home + saved passphrase</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --home</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.go-ooo_sepolia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pass</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.go-ooo_sepolia/pass.txt</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># skip a stale event-scan gap by advancing the cursor (one-shot)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --first-block</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 15114000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sepolia</span></span></code></pre></div><h2 id="day-to-day-operations" tabindex="-1">Day-to-day operations <a class="header-anchor" href="#day-to-day-operations" aria-label="Permalink to &quot;Day-to-day operations&quot;">​</a></h2><p>The admin and query commands talk to the <strong>running</strong> daemon over its <code>[serve]</code> HTTP API, authenticated with the admin bearer token (see <a href="#admin-token">Admin token</a>). All of them accept <code>--chain &lt;name|network_id&gt;</code> (or <code>--chain all</code>) when several networks are configured.</p><table tabindex="0"><thead><tr><th>Command</th><th>Purpose</th></tr></thead><tbody><tr><td><code>go-ooo query fees</code></td><td>Show your current global fee.</td></tr><tr><td><code>go-ooo query withdrawable</code></td><td>Show the <code>xFUND</code> available to withdraw.</td></tr><tr><td><code>go-ooo admin setFee &lt;fee&gt;</code></td><td>Change your global fee.</td></tr><tr><td><code>go-ooo admin setGranularFee &lt;fee&gt; &lt;consumer&gt;</code></td><td>Set a per-consumer fee.</td></tr><tr><td><code>go-ooo admin withdraw &lt;amount&gt; &lt;recipient&gt;</code></td><td>Withdraw accrued fees to an address.</td></tr><tr><td><code>go-ooo admin dex-sources sync</code></td><td>Force an immediate refresh of the DEX catalogue.</td></tr><tr><td><code>go-ooo analytics</code> / <code>go-ooo analytics suggestFee</code></td><td>Request-history analytics and a suggested break-even fee.</td></tr></tbody></table><p>Fee and amount values use the same 9-decimal <code>xFUND</code> base unit as <code>register</code>.</p><h3 id="admin-token" tabindex="-1">Admin token <a class="header-anchor" href="#admin-token" aria-label="Permalink to &quot;Admin token&quot;">​</a></h3><p>The admin HTTP API is protected by a bearer token that is independent of your keystore passphrase. Create or rotate it with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keystore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-admin-token</span></span></code></pre></div><p>Only the token&#39;s hash is stored (in a <code>0600</code> sidecar next to the keystore); the raw token is printed once. Restart <code>go-ooo</code> for a new token to take effect.</p><h2 id="multiple-networks-from-one-process" tabindex="-1">Multiple networks from one process <a class="header-anchor" href="#multiple-networks-from-one-process" aria-label="Permalink to &quot;Multiple networks from one process&quot;">​</a></h2><p>One <code>go-ooo</code> process can serve several chains, sharing a single keystore/provider key, database and pricing engine while running an independent worker per chain. Initialise the first network normally, then append each additional one with <code>--add</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mainnet</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> polygon</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --add</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> shibarium</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --add</span></span></code></pre></div><p>Each <code>--add</code> appends a <code>[[chains]]</code> entry (converting the initial <code>[chain]</code> block). Fill in each new chain&#39;s RPC URLs, then target individual chains on the admin, query and start commands with <code>--chain</code>. Network ids must be distinct.</p><h2 id="upgrading-go-ooo" tabindex="-1">Upgrading go-ooo <a class="header-anchor" href="#upgrading-go-ooo" aria-label="Permalink to &quot;Upgrading go-ooo&quot;">​</a></h2><p>When you upgrade the binary, the config schema or keystore format may have moved on:</p><ul><li><p><strong>Config</strong> — bring an existing <code>config.toml</code> up to the current schema without re-running <code>init</code> (which refuses to overwrite an existing config):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # add --dry-run to preview</span></span></code></pre></div><p>Your values are preserved, renamed settings are carried across, new sections are added with their defaults, and the previous file is backed up to <code>config.toml.bak</code>.</p></li><li><p><strong>Keystore</strong> — older releases used a legacy keystore format. Re-encrypt it to the standard go-ethereum v3 (scrypt) format under a new passphrase:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">go-ooo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keystore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span></span></code></pre></div><p>This verifies the new keystore decrypts to the same key and address before removing the old file, and issues a fresh admin token (the legacy format&#39;s token is retired with the old file).</p></li></ul><h2 id="testing-against-the-dev-environment" tabindex="-1">Testing against the dev environment <a class="header-anchor" href="#testing-against-the-dev-environment" aria-label="Permalink to &quot;Testing against the dev environment&quot;">​</a></h2><p>For a throwaway end-to-end setup, the <a href="https://github.com/unification-com/xfund-router/tree/main/docker" target="_blank" rel="noreferrer">Docker developer environment</a> runs a local <code>anvil</code> chain with the Router pre-deployed and account <code>#3</code> pre-registered as a provider. Initialise <code>go-ooo</code> with the <code>dev</code> network and import the test key printed in that environment&#39;s documentation to try the full request → fulfilment loop locally.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./ooo_api.html">OoO Data API guide</a> — the request format providers serve.</li><li><a href="./../contracts.html">Contract Addresses</a> and <a href="./../providers.html">Provider Addresses</a>.</li><li><a href="https://github.com/unification-com/xfund-router/tree/main/go-ooo#readme" target="_blank" rel="noreferrer">go-ooo README</a> — the developer-facing reference, including the <code>testapp</code> price-query and operator-report harness.</li></ul>',77)])])}const g=a(i,[["render",n]]);export{u as __pageData,g as default};
